class Solution:
    def maxPalindromesAfterOperations(self, words):
        from collections import Counter
        freq = Counter()
        for w in words:
            freq.update(w)
        pairs = sum(v // 2 for v in freq.values())
        odds = sum(v % 2 for v in freq.values())
        count = 0
        for w in sorted(words, key=len):
            n = len(w)
            need_pairs = n // 2
            if pairs >= need_pairs:
                pairs -= need_pairs
                if n % 2 == 1:
                    if odds > 0:
                        odds -= 1
                    else:
                        # borrow a pair, one goes to middle
                        if pairs > 0:
                            pairs -= 1
                            odds += 1
                            odds -= 1
                        else:
                            count += 1
                            continue
                count += 1
            # can't form palindrome for this word
        return count

