class Solution:
    def maxPalindromesAfterOperations(self, words):
        from collections import Counter
        freq = Counter(c for w in words for c in w)
        pairs = sum(v // 2 for v in freq.values())
        odds = sum(v % 2 for v in freq.values())
        count = 0
        for w in sorted(words, key=len):
            n = len(w)
            np = n // 2
            if pairs < np:
                break
            pairs -= np
            if n % 2 == 1:
                if odds > 0:
                    odds -= 1
                else:
                    pairs -= 1
                    odds += 1
                    odds -= 1
            count += 1
        return count

