var maxPalindromesAfterOperations = function(words) {
    const freq = new Array(26).fill(0);
    for (const w of words) for (const c of w) freq[c.charCodeAt(0)-97]++;
    let pairs = freq.reduce((s,v)=>s+(v>>1),0);
    let odds = freq.reduce((s,v)=>s+(v&1),0);
    let count = 0;
    const sorted = [...words].sort((a,b)=>a.length-b.length);
    for (const w of sorted) {
        const n = w.length;
        const np = n >> 1;
        if (pairs < np) break;
        pairs -= np;
        if (n & 1) {
            if (odds > 0) { odds--; }
            else { pairs--; odds++; odds--; }
        }
        count++;
    }
    return count;
};
